queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?job_title ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:tech_job_id ?cg . ?child a :TechJob ; p:id ?cg . ?l p:tech_startup_id ?pg . ?parent a :Tech_Startups ; p:id ?pg . } GROUP BY ?child }
  ?child p:job_title ?job_title .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Tech_Startups } }
  FILTER(?nf = ?total)
}

